import{_ as e,o as i,c as p,ag as r}from"./chunks/framework.DXGyWiRo.js";const n="/images/uebung002.jpg",g=JSON.parse('{"title":"Übung Lektion 2","description":"","frontmatter":{},"headers":[],"relativePath":"lektionen/uebung02.md","filePath":"lektionen/uebung02.md"}'),t={name:"lektionen/uebung02.md"};function s(u,a,d,o,h,l){return i(),p("div",null,[...a[0]||(a[0]=[r('<div class="info custom-block github-alert"><p class="custom-block-title">Zitierweise &amp; Rechte</p><p>Dieses Kapitel ist Teil des Sanskritkurses. Details zum Copyright und zur Zitierweise der Ursprungsfassung siehe: <a href="/impressum">Impressum &amp; Copyright</a></p></div><h1 id="ubung-lektion-2" tabindex="-1">Übung Lektion 2 <a class="header-anchor" href="#ubung-lektion-2" aria-label="Permalink to &quot;Übung Lektion 2&quot;">​</a></h1><p>A) Setzen Sie in den folgenden Sätzen unter Beachtung des Sandhi die angegebenen Namen und Nomina ein und bilden Sie Nominalsätze:</p><p>1. devas ... (Śiva, Agni, Viṣṇu, Gaṇeśa, Kṛṣṇa, Indra) = देवस् ... (शिव, अग्नि, विष्णु, गणेश, कृष्ण, इन्द्र)</p><p>devaḥ śivaḥ. devo &#39;gniḥ. devo viṣṇuḥ. devo gaṇeśaḥ. devaḥ kṛṣṇaḥ. deva indra.</p><p>देवः शिवः | देवो ऽग्निः | देवो विष्णुः | देवो गणेशः | देवः कृष्णः | देव इन्द्रः ||</p><p>2. dvijas ... (brāhmaṇa, kṣatriya, vaiśya) = द्विजस् ... (ब्राह्मण, क्षत्रिय, वैश्य)</p><p>dvijo brāhmaṇaḥ. dvijaḥ kṣatriyaḥ. dvijo vaiśyaḥ.</p><p>द्विजो ब्राह्मणः | द्विजः क्षत्रियः | द्विजो वैश्यः ||</p><p>3. gurus ... (brāhmaṇa, Candrakīrti) = गुरुस् ... (ब्राह्मण, चन्द्रकीर्ति)</p><p>gurur brāhmaṇaḥ. guruś candrakīrtiḥ.</p><p>गुरुर्ब्राह्मणः | गुरुश्चन्द्रकीर्तिः ||</p><p>4. vaiśyas ... (Tulādhara) = वैश्यस् ... (तुलाधर)</p><p>vaiśyas tulādharaḥ.</p><p>वैश्यस्तुलाधरः ||</p><p>5. sādhus ... (guru, Rāma) = साधुस् ... (गुरु, राम)</p><p>sādhur guruḥ. sādhū rāmaḥ.</p><p>साधुर्गुरुः | साधू रामः ||</p><p>6. kavis ... (Kālidāsa, Māgha, Bhāravi, Harṣadeva) = कविस् ... (कालिदास, माघ, भारवि, हर्षदेव)</p><p>kaviḥ kālidāsaḥ. kavir māghaḥ. kavir bhāraviḥ. kavir harṣadevaḥ.</p><p>कविः कालिदासः | कविर्माघः | कविर्भारविः | कविर्हर्षदेवः ||</p><p>B) Übersetzen Sie ins Sanskrit:</p><p>1. Rāma ist ein Brahmane.</p><p>brāhmaṇo rāmaḥ.</p><p>ब्राह्मणो रामः |</p><p>2. Der Lehrer ist ein vaiśya.</p><p>vaiśyo guruḥ.</p><p>वैश्यो गुरुः |</p><p>3. Der Śūdra ist ein heiliger Mann.</p><p>sādhuḥ śūdraḥ.</p><p>साधुः शूद्रः |</p><p>4. Der Dichter ist der Lehrer.</p><p>guruḥ kaviḥ.</p><p>गुरुः कविः |</p><p>5. Viṣṇu ist der HERR.</p><p>īśvaro viṣṇuḥ.</p><p>ईश्वरो विष्णुः |</p><p>6. Der HERR ist Śiva.</p><p>śiva īśvaraḥ.</p><p>शिव ईश्वरः |</p><p>7. Der Zweimalgeborene ist ein Brahmane.</p><p>brāhmaṇo dvijaḥ.</p><p>ब्राह्मणो द्विजः |</p><p>8. Der heilige Mann ist ein Lehrer.</p><p>guruḥ sādhuḥ.</p><p>गुरुः साधुः |</p><p>9. Der Lehrer ist ein heiliger Mann.</p><p>sādhur guruḥ.</p><p>साधुर्गुरुः ||</p><p><img src="'+n+'" alt=""><br> Abb.: īśvaraḥ śivaḥ = ईश्वरः शिवः<br> Śiva als Adrdhnārīśvara (अर्धनारीश्वर), d.h. in der Gestalt von halb Mann, halb Frau<br> [Bildquelle: Wikipedia, Public domain]</p>',50)])])}const m=e(t,[["render",s]]);export{g as __pageData,m as default};
